import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        int bufferSize = 10; // Define buffer size
        char[] buffer = new char[bufferSize]; // Buffer with limited size

        // Copy user input into buffer with proper boundary checking
        for (int i = 0; i < name.length() && i < bufferSize; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + new String(buffer).trim()); // Trim excess spaces

    }
}

